"use client";

import * as React from "react";
import { cva, type VariantProps } from "class-variance-authority";

import { cn } from "@/lib/utils";

// =============================================================================
// TYPES
// =============================================================================

interface LiveWaveformProps
  extends
    React.ComponentProps<"div">,
    VariantProps<typeof liveWaveformVariants> {
  /** Time-domain audio data (Uint8Array from getByteTimeDomainData). Values 0-255, 128 = silence. */
  data?: Uint8Array | null;
  /** Stroke color for the waveform line. Default: currentColor */
  strokeColor?: string;
  /** Line width for the waveform. Default: 2 */
  lineWidth?: number;
  /** Background color. Default: transparent */
  backgroundColor?: string;
}

// =============================================================================
// VARIANTS
// =============================================================================

const liveWaveformVariants = cva("rounded-lg overflow-hidden", {
  variants: {
    size: {
      sm: "h-16",
      md: "h-24",
      lg: "h-32",
    },
  },
  defaultVariants: {
    size: "md",
  },
});

// =============================================================================
// COMPONENT
// =============================================================================

function LiveWaveform({
  data,
  strokeColor,
  lineWidth = 2,
  backgroundColor = "transparent",
  size,
  className,
  ...props
}: LiveWaveformProps) {
  const canvasRef = React.useRef<HTMLCanvasElement>(null);
  const containerRef = React.useRef<HTMLDivElement>(null);
  const rafRef = React.useRef<number | null>(null);
  const dataRef = React.useRef<Uint8Array | null>(null);

  // Keep data ref in sync
  React.useEffect(() => {
    dataRef.current = data ?? null;
  }, [data]);

  // Draw loop
  React.useEffect(() => {
    const canvas = canvasRef.current;
    const container = containerRef.current;
    if (!canvas || !container) return;

    const ctx = canvas.getContext("2d");
    if (!ctx) return;

    // Observe container size for responsive canvas
    const resizeObserver = new ResizeObserver((entries) => {
      for (const entry of entries) {
        const { width, height } = entry.contentRect;
        const dpr = window.devicePixelRatio || 1;
        canvas.width = width * dpr;
        canvas.height = height * dpr;
        canvas.style.width = `${width}px`;
        canvas.style.height = `${height}px`;
        ctx.scale(dpr, dpr);
      }
    });
    resizeObserver.observe(container);

    const draw = () => {
      const width = canvas.width / (window.devicePixelRatio || 1);
      const height = canvas.height / (window.devicePixelRatio || 1);

      // Clear
      ctx.fillStyle = backgroundColor;
      if (backgroundColor === "transparent") {
        ctx.clearRect(0, 0, width, height);
      } else {
        ctx.fillRect(0, 0, width, height);
      }

      const audioData = dataRef.current;
      if (!audioData || audioData.length === 0) {
        // Draw flat line when no data
        ctx.beginPath();
        ctx.moveTo(0, height / 2);
        ctx.lineTo(width, height / 2);
        ctx.strokeStyle =
          strokeColor || getComputedStyle(container).color || "#888";
        ctx.lineWidth = lineWidth;
        ctx.stroke();
        rafRef.current = requestAnimationFrame(draw);
        return;
      }

      ctx.lineWidth = lineWidth;
      ctx.strokeStyle =
        strokeColor || getComputedStyle(container).color || "#888";
      ctx.beginPath();

      const bufferLength = audioData.length;
      const sliceWidth = width / bufferLength;
      let x = 0;

      for (let i = 0; i < bufferLength; i++) {
        const v = audioData[i] / 128.0; // 128 = silence
        const y = (v * height) / 2;

        if (i === 0) {
          ctx.moveTo(x, y);
        } else {
          ctx.lineTo(x, y);
        }
        x += sliceWidth;
      }

      ctx.lineTo(width, height / 2);
      ctx.stroke();

      rafRef.current = requestAnimationFrame(draw);
    };

    rafRef.current = requestAnimationFrame(draw);

    return () => {
      if (rafRef.current !== null) {
        cancelAnimationFrame(rafRef.current);
        rafRef.current = null;
      }
      resizeObserver.disconnect();
    };
  }, [strokeColor, lineWidth, backgroundColor]);

  return (
    <div
      ref={containerRef}
      data-slot="live-waveform"
      className={cn(
        "w-full text-foreground",
        liveWaveformVariants({ size }),
        className
      )}
      {...props}
    >
      <canvas
        ref={canvasRef}
        className="w-full h-full"
        aria-label="Live audio waveform"
        role="img"
      />
    </div>
  );
}

LiveWaveform.displayName = "LiveWaveform";

export { LiveWaveform, liveWaveformVariants };
export type { LiveWaveformProps };
